    return False

def parse_nested_parens(paren_string: str) -> List[int]:
    stack = []
    depths = []
    max_depth = 0

    for char in paren_string:
        if char == '(':
            stack.append(char)
            depth = len(stack)
            if depth > max_depth:
                max_depth = depth
            depths.append(depth)
        elif char == ')':
            stack.pop()
            depths.append(None)
    return depths

