def search(lst):
    # Handle edge cases listed in the spec
    if not lst:
        return -1

    # Count the frequency of each integer in the list
    freq = {}
    for num in lst:
        if num in freq:
            freq[num] += 1
        else:
            freq[num] = 1

    # Find the greatest integer that has a frequency greater than the value of the integer itself
    for i in range(max(lst), -1, -1):
        if i in freq and freq[i] > i:
            return i

    # If no such value exists, return -1
    return -1

def strange_sort_list(lst):
    if lst is None:
        return None
    elif len(lst) == 1:
        return lst
    else:
        lst.sort()
        min_val = lst[0]
        max_val = lst[-1]
        while lst[0] != min_val or lst[-1] != max_val:
            if lst[0] == min_val:
                lst.pop(0)
            if lst[-1] == max_val:
                lst.pop()
        return lst

def is_multiply_prime(a):
    def is_prime(n):
        if n < 2:
            return False
        for i in range(2, int(n**0.5) + 1):
            if n % i == 0:
                return False
        return True

    factors = []
    for i in range(2, int(a**0.5) + 1):
        if a % i == 0:
            if is_prime(i):
                factors.append(i)
            if is_prime(a // i):
                factors.append(a // i)
    factors = list(set(factors))
    return len(factors) == 3

