def encrypt(s):
    encrypted_string = ""
    for char in s:
        if char.isalpha():
            shift = 2
            char_code = ord(char.lower()) + shift
            if char.isupper():
                if char_code > ord('Z'):
                    char_code -= 26
            else:
                if char_code > ord('z'):
                    char_code -= 26
            encrypted_string += chr(char_code)
        else:
            encrypted_string += char
    return encrypted_string

