def deff(n):
    def factorial(n):
        if n == 0:
            return 1
        else:
            return n * factorial(n-1)

    def sum_of_numbers(n):
        return n * (n + 1) // 2

    result = [sum_of_numbers(i) if i % 2 == 0 else factorial(i) for i in range(1, n + 1)]
    return result

