def even_odd_palindrome(n):
    def is_palindrome(num):
        return str(num) == str(num)[::-1]

    even_count = 0
    odd_count = 0
    for i in range(1, n+1):
        if is_palindrome(i):
            if i % 2 == 0:
                even_count += 1
            else:
                odd_count += 1

    return (even_count, odd_count)

def count_nums(arr):
    count = 0
    for num in arr:
        if num >= 0:
            sum_digits = sum(int(digit) for digit in str(num))
            if sum_digits > 0:
                count += 1
        else:
            num = abs(num)
            sum_digits = sum(int(digit) for digit in str(num))
            if sum_digits > 0:
                count += 1
    return count

def move_one_ball(arr):
    if len(arr) == 0:
        return True
    if len(arr) == 1:
        return True
    if len(arr) == 2:
        return arr[0] > arr[1]
    if arr == sorted(arr):
        return True
    for i in range(len(arr)):
        temp = arr[i:] + arr[:i]
        if temp == sorted(temp):
            return True
    return False

