def minSubArraySum(nums):
    if not nums:
        return None
    if len(nums) == 1:
        return nums[0]

    min_sum = float('inf')
    for i in range(len(nums)):
        for j in range(i, len(nums)):
            sub_array = nums[i:j+1]
            if sum(sub_array) < min_sum:
                min_sum = sum(sub_array)
    return min_sum

