def add_elements(arr, k):
    # Filter the array to only include elements with at most two digits
    arr = [x for x in arr if len(str(x)) <= k]

    # If the array is empty, return 0
    if not arr:
        return 0

    # If k is greater than the length of the array, return the sum of all elements in the array
    if k > len(arr):
        return sum(arr)

    # If the array contains negative numbers, return the sum of all elements in the array
    if any(x < 0 for x in arr):
        return sum(arr)

    # Otherwise, return the sum of the first k elements in the array
    return sum(arr[:k])

