    import re
    pattern = re.compile(r'^[a-zA-Z][a-zA-Z0-9]{2,29}$')
    if pattern.match(file_name):
        return 'Yes'
    else:
        return 'No'

def sum_squares(lst):
    sum = 0
    for i in range(len(lst)):
        if i % 3 == 0 or lst[i] % 4 == 0:
            sum += lst[i] ** 2
    return sum

def words_in_sentence(sentence):
    words = sentence.split()
    return ' '.join(words)

def specialFilter(nums):
    if not nums:
        return 0
    count = 0
    for num in nums:
        if num > 10 and num % 2 == 0:
            count += 1
    return count

def get_max_triples(n):
    if n < 3:
        return 0

    a = [i for i in range(1, n + 1) if i % 3 == 0]
    count = 0

    for i in range(len(a)):
        for j in range(i + 1, len(a)):
            for k in range(j + 1, len(a)):
                if a[i] + a[j] + a[k] % 3 == 0:
                    count += 1

    return count

def double_the_difference(lst):
    sum_of_squares = 0
    for num in lst:
        if num % 2 != 0:
            sum_of_squares += num ** 2
    return sum_of_squares

def compare(game, guess):
    if len(game) != len(guess):
        raise ValueError("The lists game and guess should have the same length.")
    if not all(isinstance(i, int) for i in game) or not all(isinstance(i, int) for i in guess):
        raise ValueError("The elements in the lists game and guess should be integers.")
    return [abs(i - j) for i, j in zip(game, guess)]

def cycpattern_check(a, b):
    def is_cyclic_rotation(a, b):
        return a in b or b in a

    return is_cyclic_rotation(a, b)

def even_odd_count(num):
    if not isinstance(num, int) or num < 0:
        return (0, 0)

    even_count = 0
    odd_count = 0
    for digit in str(abs(num)):
        if int(digit) % 2 == 0:
            even_count += 1
        else:
            odd_count += 1

    return (even_count, odd_count)

def right_angle_triangle(a, b, c):
    # Check if the sides form a right-angled triangle
    if a**2 + b**2 == c**2 or a**2 + c**2 == b**2 or b**2 + c**2 == a**2:
        return True
    else:
        return False

def find_max(words):
    if not words:
        return None
    if len(words) == 1:
        return words[0]
    words.sort()
    return words[0]

def eat(number, need, remaining):
    if not isinstance(number, int) or not isinstance(need, int) or not isinstance(remaining, int):
        return None
    if number < 0 or need < 0 or remaining < 0:
        return None
    if need > remaining:
        return [number, remaining]
    else:
        return [number + need, remaining - need]

def do_algebra(operator, operand):
    if len(operator) != len(operand) - 1:
        raise Exception("Invalid input")

    result = operand[0]

    for i in range(len(operator)):
        if operator[i] == '+':
            result += operand[i + 1]
        elif operator[i] == '-':
            result -= operand[i + 1]
        elif operator[i] == '*':
            result *= operand[i + 1]
        elif operator[i] == '//':
            result //= operand[i + 1]
        elif operator[i] == '**':
            result **= operand[i + 1]

    return result

def solve(s):
    if not s:
        return ""
    elif not any(c.isalpha() for c in s):
        return ""
    else:
        return s.swapcase()

def generate_integers(a, b):
    if a < 0 or b < 0:
        return []
    if a > b:
        return []
    return list(range(a, b + 1))
